SELECT up.upgrade, count(*) AS change FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = up.bldg_id AND bs."in.nhgis_tract_gisjoin" = up."in.nhgis_tract_gisjoin" AND bs.state = up.state AND bs.upgrade = 0 WHERE bs.applicability = true AND bs.upgrade = 0 AND up.applicability = true AND up.upgrade != 0 AND coalesce(bs."out.electricity.total.energy_consumption..kwh" - up."out.electricity.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(bs."out.natural_gas.total.energy_consumption..kwh" - up."out.natural_gas.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(bs."out.other_fuel.total.energy_consumption..kwh" - up."out.other_fuel.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(bs."out.district_cooling.total.energy_consumption..kwh" - up."out.district_cooling.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(bs."out.district_heating.total.energy_consumption..kwh" - up."out.district_heating.total.energy_consumption..kwh", -1) < 0.001 AND NOT (coalesce(abs(up."out.electricity.total.energy_consumption..kwh" - bs."out.electricity.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(up."out.natural_gas.total.energy_consumption..kwh" - bs."out.natural_gas.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(up."out.other_fuel.total.energy_consumption..kwh" - bs."out.other_fuel.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(up."out.district_cooling.total.energy_consumption..kwh" - bs."out.district_cooling.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(up."out.district_heating.total.energy_consumption..kwh" - bs."out.district_heating.total.energy_consumption..kwh"), 0) < 0.001) GROUP BY 1 ORDER BY 1